// Replays the utang aging goldens generated by EXECUTING the real RN
// utangAging (mobile/lib/analytics.js) on rich fixtures: partial payments,
// legacy name rows folding into personId rows, overpaid and junk rows, and
// the oldest-due aging. A mismatch means the Dart port drifted from the app
// users trust today.

import 'dart:convert';
import 'dart:io';

import 'package:flutter_test/flutter_test.dart';
import 'package:salapify/money/utang.dart';

dynamic normalize(dynamic v) {
  if (v is Map) return v.map((k, x) => MapEntry(k.toString(), normalize(x)));
  if (v is List) return v.map(normalize).toList();
  if (v is num) {
    final d = v.toDouble();
    return d == d.roundToDouble() ? d.round() : d;
  }
  return v;
}

void main() {
  final goldens = jsonDecode(
          File('test/goldens/utang_goldens.json').readAsStringSync())
      as Map<String, dynamic>;

  for (final name in goldens.keys) {
    test('utangAging matches the RN engine on the "$name" fixture', () {
      final vector = goldens[name] as Map<String, dynamic>;
      final rawInput = vector['input'] as Map<String, dynamic>;
      final input = {
        'people': rawInput['people'] is List ? rawInput['people'] : [],
        'receivables':
            rawInput['receivables'] is List ? rawInput['receivables'] : [],
      };
      final ref = DateTime.parse(vector['ref'] as String);
      final actual = utangAging(input, ref);
      expect(normalize(actual), normalize(vector['expected']));
    });
  }
}
